"use client";

import { motion } from "framer-motion";
import { ExternalLink, Github } from "lucide-react";

const projects = [
    {
        title: "Cloud-Native E-Commerce Platform",
        description: "A highly resilient microservices architecture handling large-scale traffic, built with Spring Boot, Kafka, and Kubernetes.",
        tech: ["Java", "Spring Boot", "Kafka", "Docker", "AWS EKS"],
        github: "#",
        live: "#"
    },
    {
        title: "Serverless Analytics Pipeline",
        description: "Real-time log ingestion and analytics pipeline using AWS Lambda, Kinesis, and DynamoDB.",
        tech: ["Node.js", "AWS Lambda", "Kinesis", "Terraform", "DynamoDB"],
        github: "#",
        live: "#"
    },
    {
        title: "Distributed Caching System",
        description: "A custom distributed LRU caching layer in Go, reducing database reads by 80% under peak load.",
        tech: ["Go", "gRPC", "Redis", "Prometheus", "Grafana"],
        github: "#",
        live: "#"
    }
];

export function Projects() {
    return (
        <section id="projects" className="py-24 px-6 md:px-12 max-w-6xl mx-auto">
            <motion.div
                initial={{ opacity: 0, y: 40 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true, margin: "-100px" }}
                transition={{ duration: 0.8, ease: "easeOut" }}
            >
                <h2 className="text-4xl font-bold tracking-tight mb-12">Projects</h2>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                    {projects.map((project, index) => (
                        <motion.div
                            key={index}
                            initial={{ opacity: 0, y: 20 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            viewport={{ once: true }}
                            transition={{ duration: 0.5, delay: index * 0.1 }}
                            className="flex flex-col h-full p-6 border border-neutral-200 dark:border-neutral-800 rounded-2xl bg-neutral-50 dark:bg-neutral-900/50 hover:border-neutral-300 dark:hover:border-neutral-700 transition-colors"
                        >
                            <div className="flex justify-between items-start mb-4">
                                <h3 className="text-xl font-semibold tracking-tight">{project.title}</h3>
                                <div className="flex space-x-3 text-neutral-500">
                                    <a href={project.github} className="hover:text-black dark:hover:text-white transition-colors" aria-label="GitHub">
                                        <Github className="w-5 h-5" />
                                    </a>
                                    <a href={project.live} className="hover:text-black dark:hover:text-white transition-colors" aria-label="Live Demo">
                                        <ExternalLink className="w-5 h-5" />
                                    </a>
                                </div>
                            </div>

                            <p className="text-neutral-600 dark:text-neutral-400 font-light mb-6 flex-grow">
                                {project.description}
                            </p>

                            <div className="flex flex-wrap gap-2 mt-auto">
                                {project.tech.map((tech) => (
                                    <span
                                        key={tech}
                                        className="px-3 py-1 text-xs font-mono font-medium rounded-full bg-neutral-200/50 dark:bg-neutral-800 text-neutral-800 dark:text-neutral-300"
                                    >
                                        {tech}
                                    </span>
                                ))}
                            </div>
                        </motion.div>
                    ))}
                </div>
            </motion.div>
        </section>
    );
}
