"use client";

import { motion } from "framer-motion";

export function About() {
    return (
        <section id="about" className="py-24 px-6 md:px-12 max-w-5xl mx-auto">
            <motion.div
                initial={{ opacity: 0, y: 40 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true, margin: "-100px" }}
                transition={{ duration: 0.8, ease: "easeOut" }}
                className="flex flex-col md:flex-row gap-12 items-center"
            >
                <div className="flex-1 space-y-6">
                    <h2 className="text-4xl font-bold tracking-tight">About Me</h2>

                    <div className="space-y-4 text-lg text-neutral-600 dark:text-neutral-400 leading-relaxed font-light">
                        <p>
                            I am a Cloud-Focused Full Stack Developer specializing in building robust,
                            scalable backend systems and modern cloud-native applications.
                        </p>
                        <p>
                            My engineering philosophy centers around a scalability mindset—designing architectures
                            that not only solve today's problems but gracefully handle tomorrow's growth.
                            I thrive at the intersection of complex backend logic, distributed cloud infrastructure,
                            and seamless user experiences.
                        </p>
                        <p>
                            Whether it's designing highly available microservices, optimizing database performance,
                            or setting up CI/CD pipelines, I focus on delivering code that is secure, maintainable,
                            and impactful. Let's build something exceptional together.
                        </p>
                    </div>
                </div>

                <div className="flex-1 w-full relative">
                    <div className="aspect-square bg-neutral-200 dark:bg-neutral-800 rounded-2xl overflow-hidden relative group">
                        {/* This acts as an image placeholder since we don't have a personal photo */}
                        <div className="absolute inset-0 flex items-center justify-center bg-gradient-to-br from-neutral-100 to-neutral-300 dark:from-neutral-800 dark:to-neutral-900">
                            <span className="text-neutral-400 dark:text-neutral-600 text-6xl font-serif italic">PM</span>
                        </div>
                        <div className="absolute inset-0 border border-black/10 dark:border-white/10 rounded-2xl z-10" />
                    </div>
                    {/* Decorative shapes */}
                    <div className="absolute -bottom-6 -right-6 w-32 h-32 border border-black/10 dark:border-white/10 rounded-full -z-10" />
                    <div className="absolute -top-6 -left-6 w-24 h-24 bg-neutral-100 dark:bg-neutral-900 rounded-full -z-10" />
                </div>
            </motion.div>
        </section>
    );
}
